  1	import * as React from 'react';
  2	import { S3Context } from '@odf/core/components/s3-browser/s3-context';
  3	import { BUCKET_POLICY_CACHE_KEY_SUFFIX } from '@odf/core/constants';
  4	import { StatusBox, LoadingBox } from '@odf/shared/generic/status-box';
  5	import { S3Commands } from '@odf/shared/s3';
  6	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  7	import { useModal } from '@openshift-console/dynamic-plugin-sdk';
  8	import { useParams } from 'react-router-dom-v5-compat';
  9	import useSWRMutation from 'swr/mutation';
 10	import { CodeEditor, Language } from '@patternfly/react-code-editor';
 11	import {
 12	  Title,
 13	  Alert,
 14	  AlertActionCloseButton,
 15	  AlertVariant,
 16	  Button,
 17	  ButtonVariant,
 18	  Icon,
 19	  Tooltip,
 20	} from '@patternfly/react-core';
 21	import { PencilAltIcon } from '@patternfly/react-icons';
 22	import { t_color_blue_40 as blueInfoColor } from '@patternfly/react-tokens';
 23	import DeleteBucketPolicyModal from '../../../modals/s3-browser/bucket-policy/DeleteBucketPolicy';
 24	import SaveBucketPolicyModal from '../../../modals/s3-browser/bucket-policy/SaveBucketPolicy';
 25	import { PreConfiguredPolicies } from './PreConfiguredPolicies';
 26	import './bucket-policy.scss';
 27	
 28	type BucketPolicyProps = {
 29	  obj: { fresh: boolean; triggerRefresh: () => void };
 30	};
 31	
 32	type PolicyHeaderProps = {
 33	  success: boolean;
 34	  setSuccess: React.Dispatch<React.SetStateAction<boolean>>;
 35	};
 36	
 37	type BucketPolicyContentProps = {
 38	  triggerRefresh: () => void;
 39	} & PolicyHeaderProps;
 40	
 41	type PolicyBodyProps = {
 42	  edit: boolean;
 43	  setEdit: React.Dispatch<React.SetStateAction<boolean>>;
 44	  code: string;
 45	  setCode: React.Dispatch<React.SetStateAction<string>>;
 46	  noPolicyExists: boolean;
 47	};
 48	
 49	type PolicyFooterProps = {
 50	  noPolicyExists: boolean;
 51	  triggerRefresh: () => void;
 52	  s3Client: S3Commands;
 53	  bucketName: string;
 54	  code: string;
 55	  setCode: React.Dispatch<React.SetStateAction<string>>;
 56	  setSuccess: React.Dispatch<React.SetStateAction<boolean>>;
 57	};
 58	
 59	const policySchema = {
 60	  type: 'object',
 61	  required: ['Version', 'Statement'],
 62	  properties: {
 63	    Version: {
 64	      type: 'string',
 65	      enum: ['2012-10-17'],
 66	    },
 67	    Statement: {
 68	      type: 'array',
 69	      items: {
 70	        type: 'object',
 71	        required: ['Effect', 'Action', 'Resource', 'Principal'],
 72	        properties: {
 73	          Effect: { type: 'string', enum: ['Allow', 'Deny'] },
 74	          Action: { type: ['string', 'array'] },
 75	          Resource: { type: ['string', 'array'] },
 76	          Principal: { type: ['string', 'object'] },
 77	        },
 78	      },
 79	    },
 80	  },
 81	};
 82	
 83	const PolicyHeader: React.FC<PolicyHeaderProps> = ({ success, setSuccess }) => {
 84	  const { t } = useCustomTranslation();
 85	
 86	  return (
 87	    <>
 88	      <Title
 89	        headingLevel="h2"
 90	        size="2xl"
 91	        className="pf-v6-u-mt-lg pf-v6-u-mb-xs"
 92	      >
 93	        {t('Bucket policy')}
 94	      </Title>
 95	      <p className="pf-v6-u-mb-lg">
 96	        {t(
 97	          'Use bucket policy to grant public or restricted access to the objects stored in the bucket.'
 98	        )}
 99	      </p>
100	      {success && (
101	        <Alert
102	          isInline
103	          variant={AlertVariant.success}
104	          title={t('Bucket policy applied.')}
105	          actionClose={
106	            <AlertActionCloseButton onClose={() => setSuccess(false)} />
107	          }
108	          className="pf-v6-u-my-sm"
109	        >
110	          <p>
111	            {t(
112	              'The bucket policy has been successfully created and applied to your S3 bucket.'
113	            )}
114	          </p>
115	        </Alert>
116	      )}
117	    </>
118	  );
119	};
120	
121	const PolicyBody: React.FC<PolicyBodyProps> = ({
122	  code,
123	  setCode,
124	  edit,
125	  setEdit,
126	  noPolicyExists,
127	}) => {
128	  const { t } = useCustomTranslation();
129	
130	  const onEdit = () => {
131	    setEdit(true);
132	  };
133	  const handleEditorDidMount = (_editor, monaco) => {
134	    monaco.languages.json.jsonDefaults.setDiagnosticsOptions({
135	      validate: true,
136	      schemas: [
137	        {
138	          uri: 'https://s3.com/s3-bucket-policy-schema.json', // Unique identifier
139	          fileMatch: ['*'],
140	          schema: policySchema,
141	        },
142	      ],
143	    });
144	  };
145	
146	  const showEdit = !edit && !noPolicyExists;
147	  const isReadOnly = !edit && !!code;
148	
149	  return (
150	    <>
151	      {showEdit && (
152	        <Tooltip
153	          content={t(
154	            'Edit or delete the current bucket policy to customize access permissions or remove the existing configuration.'
155	          )}
156	        >
157	          <Button
158	            variant={ButtonVariant.link}
159	            onClick={onEdit}
160	            className="pf-v6-u-my-sm s3-policy-edit--margin"
161	          >
162	            {t('Edit bucket policy')}{' '}
163	            <Icon size="sm">
164	              <PencilAltIcon color={blueInfoColor.value} />
165	            </Icon>
166	          </Button>
167	        </Tooltip>
168	      )}
169	      {edit && <PreConfiguredPolicies setCode={setCode} />}
170	      <CodeEditor
171	        isUploadEnabled={!isReadOnly}
172	        isLanguageLabelVisible
173	        height="350px"
174	        language={Language.json}
175	        code={code}
176	        isReadOnly={isReadOnly}
177	        onCodeChange={(value: string) => {
178	          setCode(value);
179	          !edit && onEdit();
180	        }}
181	        emptyStateTitle={t('You do not have an active bucket policy.')}
182	        emptyStateBody={t(
183	          'Drag a file here, upload files, or start from scratch.'
184	        )}
185	        emptyStateButton={t('Browse')}
186	        emptyStateLink={
187	          <Button variant={ButtonVariant.link} onClick={onEdit}>
188	            {t('Start from scratch or use predefined policy configuration')}
189	          </Button>
190	        }
191	        onEditorDidMount={handleEditorDidMount}
192	        className="pf-v6-u-mt-sm pf-v6-u-mb-xl"
193	      />
194	    </>
195	  );
196	};
197	
198	const PolicyFooter: React.FC<PolicyFooterProps> = ({
199	  noPolicyExists,
200	  triggerRefresh,
201	  s3Client,
202	  bucketName,
203	  code,
204	  setCode,
205	  setSuccess,
206	}) => {
207	  const { t } = useCustomTranslation();
208	  const launcher = useModal();
209	
210	  const launchDeleteModal = () =>
211	    launcher(DeleteBucketPolicyModal, {
212	      extraProps: { bucketName, s3Client, triggerRefresh },
213	      isOpen: true,
214	    });
215	  const launchSaveModal = () =>
216	    launcher(SaveBucketPolicyModal, {
217	      extraProps: {
218	        bucketName,
219	        s3Client,
220	        triggerRefresh,
221	        policy: code,
222	        setSuccess,
223	      },
224	      isOpen: true,
225	    });
226	
227	  return (
228	    <>
229	      {noPolicyExists && (
230	        <span className="pf-v6-u-mt-sm">
231	          <Button
232	            variant={ButtonVariant.primary}
233	            onClick={launchSaveModal}
234	            className="pf-v6-u-mr-xs"
235	          >
236	            {t('Apply policy')}
237	          </Button>
238	          <Button
239	            variant={ButtonVariant.link}
240	            onClick={() => setCode('')}
241	            className="pf-v6-u-ml-xs"
242	          >
243	            {t('Clear')}
244	          </Button>
245	        </span>
246	      )}
247	      {!noPolicyExists && (
248	        <span className="pf-v6-u-mt-sm">
249	          <Button
250	            variant={ButtonVariant.secondary}
251	            onClick={launchSaveModal}
252	            className="pf-v6-u-mr-xs"
253	          >
254	            {t('Save changes')}
255	          </Button>
256	          <Button
257	            variant={ButtonVariant.secondary}
258	            onClick={launchDeleteModal}
259	            className="pf-v6-u-mr-xs pf-v6-u-ml-xs"
260	            isDanger
261	          >
262	            {t('Delete')}
263	          </Button>
264	          <Button
265	            variant={ButtonVariant.link}
266	            onClick={triggerRefresh}
267	            className="pf-v6-u-ml-xs"
268	          >
269	            {t('Cancel')}
270	          </Button>
271	        </span>
272	      )}
273	    </>
274	  );
275	};
276	
277	const BucketPolicyContent: React.FC<BucketPolicyContentProps> = ({
278	  success,
279	  setSuccess,
280	  triggerRefresh,
281	}) => {
282	  const [code, setCode] = React.useState('');
283	  const [edit, setEdit] = React.useState(false);
284	
285	  const { s3Client } = React.useContext(S3Context);
286	  const { bucketName } = useParams();
287	  const {
288	    data: policyData,
289	    error,
290	    isMutating: isLoading,
291	    trigger,
292	  } = useSWRMutation(
293	    `${s3Client.providerType}-${bucketName}-${BUCKET_POLICY_CACHE_KEY_SUFFIX}`,
294	    () => s3Client.getBucketPolicy({ Bucket: bucketName })
295	  );
296	
297	  const noPolicyExists =
298	    error?.name === 'NoSuchBucketPolicy' && !policyData?.Policy;
299	
300	  // initial fetch on first mount or remounts only
301	  React.useEffect(() => {
302	    trigger().catch((err) => {
303	      // eslint-disable-next-line no-console
304	      console.error(err);
305	    });
306	    // eslint-disable-next-line react-hooks/exhaustive-deps
307	  }, []);
308	
309	  React.useEffect(() => {
310	    if (!isLoading && !error && !!policyData?.Policy) {
311	      const unformattedPolicy = policyData?.Policy;
312	      try {
313	        const formattedPolicy = JSON.stringify(
314	          JSON.parse(unformattedPolicy),
315	          null,
316	          2
317	        );
318	        setCode(formattedPolicy);
319	      } catch {
320	        setCode(unformattedPolicy);
321	      }
322	    }
323	  }, [isLoading, error, policyData]);
324	
325	  if (isLoading || (error && !noPolicyExists)) {
326	    return <StatusBox loaded={!isLoading} loadError={error} />;
327	  }
328	
329	  return (
330	    <div className="pf-v6-u-m-sm">
331	      <PolicyHeader success={success} setSuccess={setSuccess} />
332	      <PolicyBody
333	        code={code}
334	        setCode={setCode}
335	        edit={edit}
336	        setEdit={setEdit}
337	        noPolicyExists={noPolicyExists}
338	      />
339	      {edit && (
340	        <PolicyFooter
341	          noPolicyExists={noPolicyExists}
342	          triggerRefresh={triggerRefresh}
343	          s3Client={s3Client}
344	          bucketName={bucketName}
345	          code={code}
346	          setCode={setCode}
347	          setSuccess={setSuccess}
348	        />
349	      )}
350	    </div>
351	  );
352	};
353	
354	export const BucketPolicy: React.FC<BucketPolicyProps> = ({
355	  obj: { fresh, triggerRefresh },
356	}) => {
357	  const [success, setSuccess] = React.useState(false);
358	
359	  return fresh ? (
360	    <BucketPolicyContent
361	      triggerRefresh={triggerRefresh}
362	      success={success}
363	      setSuccess={setSuccess}
364	    />
365	  ) : (
366	    <LoadingBox />
367	  );
368	};

