195	const PolicyFooter: React.FC<PolicyFooterProps> = ({
196	  noPolicyExists,
197	  triggerRefresh,
198	  s3Client,
199	  bucketName,
200	  code,
201	  setCode,
202	  setSuccess,
203	}) => {
204	  const { t } = useCustomTranslation();
205	  const launcher = useModal();
206	
207	  const launchDeleteModal = () =>
208	    launcher(DeleteBucketPolicyModal, {
209	      extraProps: { bucketName, s3Client, triggerRefresh },
210	      isOpen: true,
211	    });
212	  const launchSaveModal = () =>
213	    launcher(SaveBucketPolicyModal, {
214	      extraProps: {
215	        bucketName,
216	        s3Client,
217	        triggerRefresh,
218	        policy: code,
219	        setSuccess,
220	      },
221	      isOpen: true,
222	    });
223	
224	  return (
225	    <>
226	      {noPolicyExists && (
227	        <span className="pf-v6-u-mt-sm">
228	          <Button
229	            variant={ButtonVariant.primary}
230	            onClick={launchSaveModal}
231	            className="pf-v6-u-mr-xs"
232	          >
233	            {t('Apply policy')}
234	          </Button>
235	          <Button
236	            variant={ButtonVariant.link}
237	            onClick={() => setCode('')}
238	            className="pf-v6-u-ml-xs"
239	          >
240	            {t('Clear')}
241	          </Button>
242	        </span>
243	      )}
244	      {!noPolicyExists && (
245	        <span className="pf-v6-u-mt-sm">
246	          <Button
247	            variant={ButtonVariant.secondary}
248	            onClick={launchSaveModal}
249	            className="pf-v6-u-mr-xs"
250	          >
251	            {t('Save changes')}
252	          </Button>
253	          <Button
