257	            isDanger
258	          >
259	            {t('Delete')}
260	          </Button>
261	          <Button
262	            variant={ButtonVariant.link}
263	            onClick={triggerRefresh}
264	            className="pf-v6-u-ml-xs"
265	          >
266	            {t('Cancel')}
267	          </Button>
268	        </span>
269	      )}
270	    </>
271	  );
272	};
273	
274	const BucketPolicyContent: React.FC<BucketPolicyContentProps> = ({
275	  success,
276	  setSuccess,
277	  triggerRefresh,
278	}) => {
279	  const [code, setCode] = React.useState('');
280	  const [edit, setEdit] = React.useState(false);
281	
282	  const { s3Client } = React.useContext(S3Context);
283	  const { bucketName } = useParams();
284	  const {
285	    data: policyData,
286	    error,
287	    isMutating: isLoading,
288	    trigger,
289	  } = useSWRMutation(
290	    `${s3Client.providerType}-${bucketName}-${BUCKET_POLICY_CACHE_KEY_SUFFIX}`,
291	    () => s3Client.getBucketPolicy({ Bucket: bucketName })
292	  );
293	
294	  const noPolicyExists =
295	    error?.name === 'NoSuchBucketPolicy' && !policyData?.Policy;
296	
297	  // initial fetch on first mount or remounts only
298	  React.useEffect(() => {
299	    trigger().catch((err) => {
300	      // eslint-disable-next-line no-console
301	      console.error(err);
302	    });
303	    // eslint-disable-next-line react-hooks/exhaustive-deps
304	  }, []);
305	
306	  React.useEffect(() => {
307	    if (!isLoading && !error && !!policyData?.Policy) {
308	      const unformattedPolicy = policyData?.Policy;
309	      try {
310	        const formattedPolicy = JSON.stringify(
311	          JSON.parse(unformattedPolicy),
312	          null,
313	          2
314	        );
315	        setCode(formattedPolicy);
316	      } catch {
317	        setCode(unformattedPolicy);
318	      }
319	    }
320	  }, [isLoading, error, policyData]);
321	
322	  if (isLoading || (error && !noPolicyExists)) {
323	    return <StatusBox loaded={!isLoading} loadError={error} />;
324	  }
325	
326	  return (
327	    <div className="pf-v6-u-m-sm">
328	      <PolicyHeader success={success} setSuccess={setSuccess} />
329	      <PolicyBody
330	        code={code}
331	        setCode={setCode}
332	        edit={edit}
333	        setEdit={setEdit}
334	        noPolicyExists={noPolicyExists}
335	      />
336	      {edit && (
337	        <PolicyFooter
338	          noPolicyExists={noPolicyExists}
339	          triggerRefresh={triggerRefresh}
340	          s3Client={s3Client}
341	          bucketName={bucketName}
342	          code={code}
343	          setCode={setCode}
344	          setSuccess={setSuccess}
345	        />
346	      )}
347	    </div>
348	  );
349	};
350	
351	export const BucketPolicy: React.FC<BucketPolicyProps> = ({
352	  obj: { fresh, triggerRefresh },
353	}) => {
354	  const [success, setSuccess] = React.useState(false);
355	
356	  return fresh ? (
357	    <BucketPolicyContent
358	      triggerRefresh={triggerRefresh}
359	      success={success}
360	      setSuccess={setSuccess}
361	    />
362	  ) : (
363	    <LoadingBox />
364	  );
365	};

